	"myapp/view/DeliveryPlanList.view.xml":'<mvc:View\r\n    controllerName="myapp.controller.DeliveryPlanList"\r\n    xmlns:mvc="sap.ui.core.mvc"\r\n    xmlns="sap.m"><Page title="{i18n>deliveryPlanListTitle}" showNavButton="true" navButtonPress="onNavBack"><subHeader><Toolbar><Button icon="sap-icon://add" text="新增" press="onAdd" type="Emphasized" /><SearchField placeholder="{i18n>filterPlaceholder}" search="onSearch" width="100%" /></Toolbar></subHeader><content><Table id="deliveryTable" class="supplierTable" items="{deliveryPlans>/deliveryPlans}"><columns><Column><Text text="{i18n>deliveryId}" /></Column><Column><Text text="{i18n>deliveryDate}" /></Column><Column><Text text="{i18n>deliveryStatus}" /></Column><Column><Text text="{i18n>poId}" /></Column></columns><items><ColumnListItem type="Navigation" press="onItemPress"><cells><Text text="{deliveryPlans>id}" /><Text text="{deliveryPlans>date}" /><Text text="{deliveryPlans>status}" /><Link text="{deliveryPlans>purchaseOrderId}" press="onNavigateToPurchaseOrder" /><HBox><Button text="查看" press="onViewPress" /><Button text="编辑" press="onEditPress" /><Button icon="sap-icon://delete" type="Reject" press="onDeletePress" /></HBox></cells></ColumnListItem></items></Table></content><Dialog id="dpDialog" title="送货计划管理" type="Standard"><content><VBox spacing="1rem" class="sapUiContentPadding"><Label text="计划号" required="true" /><Input id="dpPlanNumberInput" value="{oNewDP>/planNumber}" /><Label text="采购订单" /><Input id="dpPOInput" value="{oNewDP>/purchaseOrderId}" /><Label text="送货日期" /><Input id="dpDateInput" value="{oNewDP>/deliveryDate}" /><Label text="数量" /><Input id="dpQtyInput" value="{oNewDP>/quantity}" type="Number" /><Label text="状态" /><Input id="dpStatusInput" value="{oNewDP>/status}" /></VBox></content><beginButton><Button text="保存" press="onDialogSave" type="Emphasized" /></beginButton><endButton><Button text="取消" press="onDialogCancel" /></endButton></Dialog></Page></mvc:View>',
	"myapp/view/DeploymentList.view.xml":'<mvc:View\r\n    controllerName="myapp.controller.DeploymentList"\r\n    xmlns:mvc="sap.ui.core.mvc"\r\n    xmlns="sap.m"\r\n    xmlns:core="sap.ui.core"><Page title="部署管理" showNavButton="true" navButtonPress="onNavBack"><VBox class="sapUiContentPadding" width="100%"><Text text="部署列表" class="sapUiTinyMarginBottom" /><Table items="{process>/deployments}"><columns><Column><Text text="部署ID" /></Column><Column><Text text="模型名称" /></Column><Column><Text text="部署时间" /></Column><Column><Text text="状态" /></Column></columns><items><ColumnListItem><cells><Text text="{process>id}" /><Text text="{process>modelName}" /><Text text="{process>deployTime}" /><Text text="{process>status}" /></cells></ColumnListItem></items></Table></VBox></Page></mvc:View>',
